Replace an existing financial memory by id in Finances. Use this to fully replace the nested `memory` payload; future Finances behavior will use the new memory definition after any relevant background refreshes complete. Use `memory_type="rule"` for transaction row rewriting: match rows with QueryOperand filters, then apply ordered actions like set, multiply, add, hide, or delete. `memory_type="data_rows"` stores manual rows for a query scope. `memory_type="budget"` stores budget memories. `memory_type="savings_goal"` stores net-worth goal memories. `memory_type="asset"` is only for manually tracked non-monetary assets that are not better represented as holdings, such as homes, vehicles, private businesses, or collectibles. Monetary assets such as cash, stocks, bonds, crypto, or anything with a ticker symbol should be stored as `memory_type="data_rows"` for investment_holdings (`scope="investments"`) so they appear in `query_investment_holdings`, not as `asset` memories. `memory` is a `LedgerFinancialMemoryDataWrapper`. Each `memory` payload must match this authoritative TypeScript reference; `memory.data.memory_type` selects the memory variant, and budget `tracking_type` selects the tracking variant:
```ts
type Integer = number;
type QueryPrimitiveValue = string | Integer | number | boolean;
type QueryOperandValue = QueryPrimitiveValue | null | Array<QueryPrimitiveValue | null>;

interface QueryOperand {
  /** Operator for the filter (eq, neq, gt, gte, lt, lte, between, in, contains, not_contains). */
  op: "eq" | "neq" | "gt" | "gte" | "lt" | "lte" | "between" | "in" | "contains" | "not_contains";
  /** Value for the operator. Use a list for in/between. */
  val: string | Integer | number | boolean | Array<string | Integer | number | boolean | null> | null;
}

interface LedgerTransactionRuleAction {
  operation: "set" | "multiply" | "add" | "delete" | "hide";
  /** Default: null. */
  field?: string | null;
  /** Default: null. */
  value?: string | Integer | number | boolean | Array<string | Integer | number | boolean | null> | null;
}

interface LedgerFinancialMemoryBudgetTrackingPeriodic {
  /** Default: "periodic". */
  tracking_type: "periodic";
  period: "daily" | "weekly" | "monthly" | "yearly";
}

interface LedgerFinancialMemoryBudgetTrackingOneOff {
  /** Default: "one_off". */
  tracking_type: "one_off";
  /** Default: null. */
  start_date?: string | null;
}

type LedgerFinancialMemoryBudgetTracking = LedgerFinancialMemoryBudgetTrackingPeriodic | LedgerFinancialMemoryBudgetTrackingOneOff;

interface LedgerFinancialMemoryBudgetCategory {
  /** User-facing display name for this budget category. Use a human-readable label such as 'Bills & Utilities' or 'Family & Kids', not canonical category ids such as 'bills_utilities', 'family_kids', or 'financial'. Put machine-readable category matching in `filters`. */
  name: string;
  filters?: Record<string, QueryOperand>;
  /** Minimum: 0. */
  limit: number;
}

interface LedgerFinancialMemorySavingsGoalAccountTypes {
  excluded_account_types?: Array<"brokerage" | "mortgage">;
}

type LedgerFinancialMemoryAssetCategory = "real_estate_primary_home" | "real_estate_secondary_home" | "real_estate_rental" | "vehicle_car" | "vehicle_motorcycle" | "vehicle_boat" | "vehicle_rv" | "vehicle_plane" | "vehicle_helicopter" | "cash_and_equivalents" | "retirement_account" | "private_business" | "private_equity" | "commodity" | "collectible_art" | "collectible_jewelry" | "collectible_watch" | "collectible_other" | "insurance_cash_value" | "intellectual_property" | "trust_asset" | "receivable" | "other";

interface LedgerFinancialMemoryDataBase {
  /** Default: null. */
  human_description?: string | null;
  human_name: string;
}

interface LedgerFinancialMemoryDataRule extends LedgerFinancialMemoryDataBase {
  /** Default: "rule". */
  memory_type: "rule";
  scope: "transactions" | "recurring_transactions" | "investments" | "investment_transactions" | "liabilities" | "accounts" | "assets";
  filters?: Record<string, QueryOperand>;
  actions?: Array<LedgerTransactionRuleAction>;
}

interface LedgerFinancialMemoryDataRows extends LedgerFinancialMemoryDataBase {
  /** Default: "data_rows". */
  memory_type: "data_rows";
  scope: "transactions" | "recurring_transactions" | "investments" | "investment_transactions" | "liabilities" | "accounts" | "assets";
  /** Maximum items: 100. */
  rows?: Array<Record<string, unknown>>;
}

interface LedgerFinancialMemoryDataBudget extends LedgerFinancialMemoryDataBase {
  /** Default: "budget". */
  memory_type: "budget";
  budget_id: string;
  /** Default: null. */
  budget_name?: string | null;
  tracking: LedgerFinancialMemoryBudgetTrackingPeriodic | LedgerFinancialMemoryBudgetTrackingOneOff;
  /** Minimum items: 1. */
  categories: Array<LedgerFinancialMemoryBudgetCategory>;
}

interface LedgerFinancialMemoryDataAsset extends LedgerFinancialMemoryDataBase {
  /** Default: "asset". */
  memory_type: "asset";
  /** Default: null. */
  asset_name?: string | null;
  /** Default: null. */
  asset_description?: string | null;
  asset_category: LedgerFinancialMemoryAssetCategory;
  /** Minimum: 0. */
  current_worth: number;
  /** Default: null. */
  cost_basis?: number | null;
  /** Default: "USD". */
  currency?: string | null;
  /** Default: null. */
  acquire_date?: string | null;
  /** Default: null. */
  sell_date?: string | null;
}

interface LedgerFinancialMemoryDataSavingsGoal extends LedgerFinancialMemoryDataBase {
  /** Default: "savings_goal". */
  memory_type: "savings_goal";
  account_types?: LedgerFinancialMemorySavingsGoalAccountTypes | null;
  target_net_worth: number;
  target_date: string;
  savings_goal_name: string;
  savings_goal_description: string;
  monthly_planned_contribution: number;
  /** Plan on how the user will accomplish this goal. This could be a monthly contribution scheme, savings scheme, or anything. */
  plan: string | null;
}

type LedgerFinancialMemoryData = LedgerFinancialMemoryDataRule | LedgerFinancialMemoryDataRows | LedgerFinancialMemoryDataBudget | LedgerFinancialMemoryDataAsset | LedgerFinancialMemoryDataSavingsGoal;

interface LedgerFinancialMemoryDataWrapper {
  data: LedgerFinancialMemoryDataRule | LedgerFinancialMemoryDataRows | LedgerFinancialMemoryDataBudget | LedgerFinancialMemoryDataAsset | LedgerFinancialMemoryDataSavingsGoal;
}
```

